/*! Highlight.js v11.9.0 - Minimal version for documentation */
(function() {
  // Simple syntax highlighting for common languages
  
  const hljs = {
    highlightAll: function() {
      document.querySelectorAll('pre code').forEach(block => {
        this.highlightElement(block);
      });
    },
    
    highlightElement: function(element) {
      const code = element.textContent;
      const lang = element.parentElement.className.match(/language-(\w+)/)?.[1] || 'plaintext';
      
      element.innerHTML = this.highlight(code, lang).value;
      element.parentElement.classList.add('hljs');
    },
    
    highlight: function(code, lang) {
      const highlighted = this.highlightCode(code, lang);
      return { value: highlighted };
    },
    
    highlightCode: function(code, lang) {
      // Remove existing HTML
      const div = document.createElement('div');
      div.textContent = code;
      code = div.innerHTML;
      
      // Basic keyword highlighting for common languages
      const keywords = {
        php: ['<?php', '<?', '?>', 'echo', 'return', 'if', 'else', 'foreach', 'for', 'while', 'function', 'class', 'public', 'private', 'protected', 'const', 'static', 'new', 'array', 'string', 'int', 'bool', 'float'],
        javascript: ['const', 'let', 'var', 'function', 'return', 'if', 'else', 'for', 'while', 'switch', 'case', 'break', 'continue', 'class', 'extends', 'this', 'new', 'async', 'await', 'import', 'export', 'default'],
        html: ['<!DOCTYPE', 'html', 'head', 'body', 'div', 'span', 'p', 'h1', 'h2', 'h3', 'a', 'img', 'script', 'style', 'meta', 'link'],
        css: ['body', 'color', 'background', 'margin', 'padding', 'font', 'border', 'width', 'height', 'display', 'flex', 'grid', '@media', '@import', '@font-face'],
      };
      
      const keywordList = keywords[lang] || [];
      
      // Escape HTML special chars and apply highlighting
      keywordList.forEach(keyword => {
        const regex = new RegExp(`\\b(${keyword})\\b`, 'g');
        code = code.replace(regex, '<span class="hljs-keyword">$1</span>');
      });
      
      // Highlight strings
      code = code.replace(/(['"`])([^\1]*?)\1/g, '<span class="hljs-string">$&</span>');
      
      // Highlight comments
      code = code.replace(/\/\/.*$/gm, '<span class="hljs-comment">$&</span>');
      code = code.replace(/\/\*[\s\S]*?\*\//g, '<span class="hljs-comment">$&</span>');
      code = code.replace(/#.*$/gm, '<span class="hljs-comment">$&</span>');
      
      // Highlight numbers
      code = code.replace(/\b(\d+)\b/g, '<span class="hljs-number">$1</span>');
      
      // Highlight function/class names
      code = code.replace(/\b(function|class)\s+(\w+)/g, '<span class="hljs-keyword">$1</span> <span class="hljs-title">$2</span>');
      
      return code;
    }
  };
  
  window.hljs = hljs;
})();

// Auto-highlight on load
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', function() {
    hljs.highlightAll();
  });
} else {
  hljs.highlightAll();
}
